  7	} from '@catalog/CreateFromInstanceTypes/state/utils/types';
  8	import FolderSelect from '@kubevirt-utils/components/FolderSelect/FolderSelect';
  9	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
 10	import { validateVMName } from '@kubevirt-utils/components/VMNameValidationHelperText/utils/utils';
 11	import VMNameValidationHelperText from '@kubevirt-utils/components/VMNameValidationHelperText/VMNameValidationHelperText';
 12	import { TREE_VIEW_FOLDERS } from '@kubevirt-utils/hooks/useFeatures/constants';
 13	import { useFeatures } from '@kubevirt-utils/hooks/useFeatures/useFeatures';
 14	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 15	import { convertResourceArrayToMap } from '@kubevirt-utils/resources/shared';
 16	import { isEmpty } from '@kubevirt-utils/utils/utils';
 17	import { DescriptionList, TextInput } from '@patternfly/react-core';
 18	
 19	import { getCPUAndMemoryFromDefaultInstanceType, getOSFromDefaultPreference } from '../utils/utils';
 20	
 21	type DetailsLeftGridProps = {
 22	  instanceTypesAndPreferencesData: UseInstanceTypeAndPreferencesValues;
 23	};
 24	
 25	const DetailsLeftGrid: FC<DetailsLeftGridProps> = ({ instanceTypesAndPreferencesData }) => {
 26	  const { t } = useKubevirtTranslation();
 27	  const { featureEnabled: treeViewFoldersEnabled } = useFeatures(TREE_VIEW_FOLDERS);
 28	
 29	  const { instanceTypeVMState, setInstanceTypeVMState, vmNamespaceTarget } =
 30	    useInstanceTypeVMStore();
 31	  const { folder, selectedBootableVolume, selectedInstanceType, vmName } = instanceTypeVMState;
 32	  const { clusterInstanceTypes, preferences } = instanceTypesAndPreferencesData;
 33	
 34	  const preferencesMap = useMemo(() => convertResourceArrayToMap(preferences), [preferences]);
 35	  const instanceTypesMap = useMemo(
 36	    () => convertResourceArrayToMap(clusterInstanceTypes),
 37	    [clusterInstanceTypes],
 38	  );
 39	
 40	  const vmNameValidated = validateVMName(vmName);
 41	
 42	  const operatingSystem = getOSFromDefaultPreference(selectedBootableVolume, preferencesMap);
 43	  const cpuMemoryString = !isEmpty(instanceTypesMap?.[selectedInstanceType?.name])
 44	    ? getCPUAndMemoryFromDefaultInstanceType(instanceTypesMap[selectedInstanceType?.name])
 45	    : null;
 46	
 47	  return (
 48	    <DescriptionList className="pf-v6-c-description-list" isHorizontal>
 49	      <VirtualMachineDescriptionItem
 50	        descriptionData={
 51	          <>
 52	            <TextInput
 53	              onChange={(_event, newVMName) =>
 54	                setInstanceTypeVMState({
 55	                  payload: newVMName,
 56	                  type: instanceTypeActionType.setVMName,
 57	                })
 58	              }
 59	              aria-label="instancetypes virtualmachine name"
 60	              data-test-id="instancetypes-vm-name-input"
 61	              isRequired
 62	              name="vmname"
 63	              type="text"
 64	              validated={vmNameValidated}
 65	              value={vmName}
 66	            />
 67	            <VMNameValidationHelperText vmName={vmName} />
 68	          </>
 69	        }
 70	        descriptionHeader={t('Name')}
 71	      />
 72	      {treeViewFoldersEnabled && (
 73	        <VirtualMachineDescriptionItem
 74	          descriptionData={
 75	            <FolderSelect
 76	              setSelectedFolder={(newFolder) => {
 77	                setInstanceTypeVMState({
 78	                  payload: newFolder,
 79	                  type: instanceTypeActionType.setFolder,
 80	                });
 81	              }}
 82	              isFullWidth
 83	              namespace={vmNamespaceTarget}
 84	              selectedFolder={folder}
 85	            />
 86	          }
 87	          descriptionHeader={t('Folder')}
 88	        />
 89	      )}
 90	      <VirtualMachineDescriptionItem
 91	        descriptionData={operatingSystem}
 92	        descriptionHeader={t('Operating system')}
 93	      />
 94	      <VirtualMachineDescriptionItem
 95	        descriptionData={selectedInstanceType?.name}
 96	        descriptionHeader={t('InstanceType')}
 97	      />
 98	      <VirtualMachineDescriptionItem
 99	        descriptionData={cpuMemoryString}
100	        descriptionHeader={t('CPU | Memory')}
101	      />
102	    </DescriptionList>
103	  );
104	};
105	
106	export default DetailsLeftGrid;

